export interface Medicine {
  id: string;
  name: string;
  dosage: string;
  time: string; // HH:mm format
  frequency: 'daily' | 'weekly' | 'custom';
  instructions: string;
  startDate: string;
  category: 'tablet' | 'syrup' | 'injection' | 'other';
}

export interface IntakeLog {
  id: string;
  medicineId: string;
  timestamp: string;
  status: 'taken' | 'missed' | 'delayed';
  note?: string;
}

export interface AppState {
  role: UserRole;
  medicines: Medicine[];
  logs: IntakeLog[];
}

