import React from 'react';
import { Medicine, IntakeLog } from '../types';
import { Icons } from '../constants';

interface PatientDashboardProps {
  medicines: Medicine[];
  logs: IntakeLog[];
  onMarkStatus: (medicineId: string, status: 'taken' | 'missed') => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ medicines, logs, onMarkStatus }) => {
  const sortedMeds = [...medicines].sort((a, b) => a.time.localeCompare(b.time));
  const today = new Date().toISOString().split('T')[0];

  const getStatusForToday = (medId: string) => {
    return logs.find(l => l.medicineId === medId && l.timestamp.startsWith(today))?.status;
  };

  return (
    <div className="space-y-8">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Good Morning, John</h1>
          <p className="text-slate-500 mt-1">You have {medicines.length} medicines scheduled for today.</p>
        </div>
        <div className="text-right">
          <p className="text-sm font-medium text-slate-500">{new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</p>
        </div>
      </header>

      {/* Reminder Banner */}
      <div className="bg-blue-600 rounded-2xl p-6 text-white flex items-center justify-between shadow-xl shadow-blue-100">
        <div>
          <h2 className="text-xl font-bold mb-1">Next Dose in 15 mins</h2>
          <p className="opacity-90">Metformin - 500mg (Post-Breakfast)</p>
        </div>
        <div className="bg-white/20 p-4 rounded-full">
          <Icons.Bell />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Timeline */}
        <div className="lg:col-span-2 space-y-4">
          <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <Icons.Calendar />
            Today's Schedule
          </h3>

          <div className="space-y-4 relative">
            <div className="absolute left-6 top-4 bottom-4 w-0.5 bg-slate-100 -z-10"></div>
            {sortedMeds.map((med) => {
              const status = getStatusForToday(med.id);
              return (
                <div key={med.id} className="flex gap-4">
                  <div className={`w-12 h-12 rounded-full flex items-center justify-center z-10 shadow-sm transition-colors ${
                    status === 'taken' ? 'bg-emerald-500 text-white' :
                    status === 'missed' ? 'bg-rose-500 text-white' : 'bg-white text-slate-400 border border-slate-200'
                  }`}>
                    {status === 'taken' ? <Icons.Check /> : status === 'missed' ? <Icons.X /> : <span>{med.time.split(':')[0]}</span>}
                  </div>

                  <div className="flex-1 bg-white border border-slate-200 rounded-2xl p-4 shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="flex items-center gap-2">
                          <span className="text-sm font-bold text-blue-600 uppercase tracking-wide">{med.time}</span>
                          <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                          <span className="text-sm text-slate-500">{med.dosage}</span>
                        </div>
                        <h4 className="text-lg font-bold text-slate-800">{med.name}</h4>
                        <p className="text-sm text-slate-500 italic mt-1">{med.instructions}</p>
                      </div>

                      {!status && (
                        <div className="flex gap-2">
                          <button 
                            onClick={() => onMarkStatus(med.id, 'taken')}
                            className="bg-emerald-50 text-emerald-600 p-2 rounded-lg hover:bg-emerald-100 transition-colors"
                          >
                            <Icons.Check />
                          </button>
                          <button 
                            onClick={() => onMarkStatus(med.id, 'missed')}
                            className="bg-rose-50 text-rose-600 p-2 rounded-lg hover:bg-rose-100 transition-colors"
                          >
                            <Icons.X />
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats & Actions */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4">Weekly Adherence</h3>
            <div className="flex items-end justify-between h-32 gap-2">
              {[65, 80, 40, 90, 100, 75, 95].map((val, i) => (
                <div key={i} className="flex-1 flex flex-col items-center gap-2">
                  <div className="w-full bg-slate-50 rounded-md overflow-hidden flex flex-col justify-end h-full">
                    <div className={`w-full ${val > 80 ? 'bg-emerald-500' : val > 50 ? 'bg-blue-500' : 'bg-rose-500'}`} style={{ height: `${val}%` }}></div>
                  </div>
                  <span className="text-[10px] font-bold text-slate-400">MTWTFSS'[i]</span>
