export default PatientDashboard;

import React, { useState, useRef, useEffect } from 'react';
import { Icons } from '../constants';
import { getGeminiAdvisor } from '../services/geminiService';

const MediBot: React.FC = () => {
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: 'Hello John! I am MediBot. How can I help you with your health or medicines today?' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const response = await getGeminiAdvisor(userMsg);
      setMessages(prev => [...prev, { role: 'bot', text: response || "I'm sorry, I couldn't process that. Please try again." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "Error connecting to AI. Please check your internet." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-160px)] flex flex-col bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden">
      <div className="p-4 border-b border-slate-100 bg-slate-50 flex items-center gap-3">
        <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white">
          <Icons.Bot />
        </div>
        <div>
          <h2 className="font-bold text-slate-800">MediBot AI</h2>
          <p className="text-xs text-emerald-500 font-medium flex items-center gap-1">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span> Online
          </p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm ${
              m.role === 'user' 
              ? 'bg-blue-600 text-white rounded-tr-none' 
              : 'bg-slate-100 text-slate-800 rounded-tl-none'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-slate-100 rounded-2xl px-4 py-3 text-slate-400 text-sm italic flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce delay-150"></div>
              MediBot is thinking...
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2">
          <input 
            type="text" 
            placeholder="Ask about side effects, dosage, or health tips..."
            className="flex-1 bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={loading}
            className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200 disabled:opacity-50"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg>
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-2 italic">
          AI assistant may provide inaccurate info. Always verify with your doctor.
        </p>
      </div>
    </div>
  );
};

export default MediBot;

import React, { useState, useEffect } from 'react';
import { Medicine, IntakeLog } from '../types';
import { Icons } from '../constants';
import { getAdherenceReport } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DoctorReportsProps {
  medicines: Medicine[];
  logs: IntakeLog[];
}

const DoctorReports: React.FC<DoctorReportsProps> = ({ medicines, logs }) => {
  const [aiAnalysis, setAiAnalysis] = useState<{summary: string, score: number, alerts: string[]} | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchReport = async () => {
      setLoading(true);
      try {
        const report = await getAdherenceReport(logs, medicines);
        setAiAnalysis(report);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchReport();
  }, [logs, medicines]);

  // Aggregate data for chart
  const data = medicines.map(med => {
    const medLogs = logs.filter(l => l.medicineId === med.id);
    const takenCount = medLogs.filter(l => l.status === 'taken').length;
    const missedCount = medLogs.filter(l => l.status === 'missed').length;
    const total = takenCount + missedCount || 1;
    return {
      name: med.name,
      adherence: Math.round((takenCount / total) * 100),
      missed: missedCount
    };
  });

  return (
    <div className="space-y-8">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Compliance Analytics</h1>
        <p className="text-slate-500">Monitoring adherence for patient: John Doe (ID: #4928)</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Compliance Score Card */}
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center">
          <div className="relative w-48 h-48 flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="96" cy="96" r="88" stroke="currentColor" strokeWidth="12" fill="transparent" className="text-slate-100" />
              <circle 
                cx="96" cy="96" r="88" stroke="currentColor" strokeWidth="12" fill="transparent" 
                strokeDasharray={552}
                strokeDashoffset={552 - (552 * (aiAnalysis?.score || 0)) / 100}
                className={`${(aiAnalysis?.score || 0) > 80 ? 'text-emerald-500' : 'text-blue-500'} transition-all duration-1000 ease-out`}
              />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-4xl font-black text-slate-800">{aiAnalysis?.score || '--'}%</span>
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Compliance</span>
            </div>
          </div>
          <p className="mt-6 text-slate-600 font-medium">
            Based on the last 30 days of medical logs.
          </p>
        </div>

        {/* AI Analysis Card */}
        <div className="bg-slate-900 text-white p-8 rounded-3xl shadow-xl shadow-slate-200 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-10">
            <Icons.Bot />
          </div>
          <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
            <Icons.Bot />
            MediBot Smart Summary
          </h3>
          {loading ? (
            <div className="space-y-4 animate-pulse">
