import React, { useMemo } from 'react';
import { Medicine, IntakeLog } from '../types';
import { Icons } from '../constants';

interface PatientDashboardProps {
  medicines: Medicine[];
  logs: IntakeLog[];
  onMarkStatus: (medicineId: string, status: 'taken' | 'missed') => void;
  userName: string;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ medicines, logs, onMarkStatus, userName }) => {
  const sortedMeds = useMemo(() => [...medicines].sort((a, b) => a.time.localeCompare(b.time)), [medicines]);
  const today = new Date().toISOString().split('T')[0];

  const getStatusForToday = (medId: string) => {
    return logs.find(l => l.medicineId === medId && l.timestamp.startsWith(today))?.status;
  };

  const nextDoseInfo = useMemo(() => {
    const now = new Date();
    const currentHHmm = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');

    const next = sortedMeds.find(m => {
      const status = getStatusForToday(m.id);
      return m.time > currentHHmm && !status;
    });

    if (!next) return null;

    const [h, m] = next.time.split(':').map(Number);
    const target = new Date();
    target.setHours(h, m, 0);
    const diffMs = target.getTime() - now.getTime();
    const diffMins = Math.round(diffMs / 60000);

    return { medicine: next, minutes: diffMins };
  }, [sortedMeds, logs]);

  const firstName = userName.split(' ')[0];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Hello, {firstName}</h1>
          <p className="text-slate-500 mt-1 font-medium">You have {medicines.length} medicines scheduled for today.</p>
        </div>
        <div className="text-right hidden sm:block">
          <p className="text-sm font-bold text-slate-800">{new Date().toLocaleDateString('en-US', { weekday: 'long' })}</p>
          <p className="text-xs font-medium text-slate-400">{new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric' })}</p>
        </div>
      </header>

      <div className={`rounded-[2.5rem] p-8 text-white flex items-center justify-between shadow-2xl transition-all duration-500 relative overflow-hidden ${
        nextDoseInfo ? 'bg-blue-600 shadow-blue-200' : 'bg-slate-800 shadow-slate-200'
      }`}>
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10">
          {nextDoseInfo ? (
            <>
              <h2 className="text-2xl font-black mb-1">Next Dose in {nextDoseInfo.minutes} mins</h2>
              <p className="opacity-90 font-medium">{nextDoseInfo.medicine.name} • {nextDoseInfo.medicine.dosage}</p>
              <div className="mt-4 flex items-center gap-2 text-xs font-bold uppercase tracking-widest bg-white/20 w-fit px-3 py-1 rounded-full">
                <Icons.Bell /> Reminder set
              </div>
            </>
          ) : (
            <>
              <h2 className="text-2xl font-black mb-1">All clear for now!</h2>
              <p className="opacity-90 font-medium">No upcoming doses scheduled for today.</p>
            </>
          )}
        </div>
        <div className="relative z-10 bg-white/10 p-5 rounded-3xl backdrop-blur-md hidden sm:block">
          {nextDoseInfo ? <Icons.Bell /> : <Icons.Check />}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-4">
          <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center">
              <Icons.Calendar />
            </div>
            Today's Schedule
          </h3>

          <div className="space-y-4 relative">
            <div className="absolute left-6 top-4 bottom-4 w-0.5 bg-slate-100 -z-10"></div>
            {sortedMeds.length === 0 ? (
              <div className="bg-white p-12 rounded-[2rem] border-2 border-dashed border-slate-100 text-center">
                <p className="text-slate-400 font-bold">No medicines scheduled yet.</p>
              </div>
            ) : (
              sortedMeds.map((med) => {
                const status = getStatusForToday(med.id);
                return (
                  <div key={med.id} className="flex gap-4 group">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center z-10 shadow-sm transition-all duration-500 border-4 border-slate-50 ${
                      status === 'taken' ? 'bg-emerald-500 text-white' :
                      status === 'missed' ? 'bg-rose-500 text-white' : 'bg-white text-slate-400 border-white'
                    }`}>
                      {status === 'taken' ? <Icons.Check /> : status === 'missed' ? <Icons.X /> : <span className="font-black">{med.time.split(':')[0]}</span>}
                    </div>

                    <div className={`flex-1 bg-white border-2 rounded-[1.5rem] p-5 transition-all duration-300 ${
                      status === 'taken' ? 'border-emerald-100 opacity-60 grayscale-[0.5]' : 
                      status === 'missed' ? 'border-rose-100' : 'border-slate-50 shadow-sm hover:shadow-xl hover:border-blue-100'
                    }`}>
                      <div className="flex justify-between items-start">
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className={`text-xs font-black uppercase tracking-widest ${status === 'taken' ? 'text-emerald-500' : 'text-blue-600'}`}>{med.time}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <span className="text-xs font-bold text-slate-400">{med.dosage}</span>
                          </div>
                          <h4 className={`text-lg font-black ${status === 'taken' ? 'text-slate-400 line-through' : 'text-slate-800'}`}>{med.name}</h4>
                          {med.instructions && <p className="text-sm text-slate-500 font-medium mt-1">{med.instructions}</p>}
                        </div>

                        {!status && (
                          <div className="flex gap-2">
                            <button 
                              onClick={() => onMarkStatus(med.id, 'taken')}
                              className="bg-emerald-50 text-emerald-600 p-3 rounded-xl hover:bg-emerald-500 hover:text-white transition-all shadow-sm active:scale-90"
                              title="Mark as Taken"
                            >
                              <Icons.Check />
                            </button>
                            <button 
                              onClick={() => onMarkStatus(med.id, 'missed')}
                              className="bg-rose-50 text-rose-600 p-3 rounded-xl hover:bg-rose-500 hover:text-white transition-all shadow-sm active:scale-90"
                              title="Mark as Missed"
                            >
                              <Icons.X />
                            </button>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
            <h3 className="font-black text-slate-800 mb-6 flex items-center justify-between">
              Adherence Rate
              <span className="text-blue-600 text-sm">92%</span>
            </h3>
            <div className="flex items-end justify-between h-32 gap-2">
              {[65, 80, 40, 90, 100, 75, 95].map((val, i) => (
                <div key={i} className="flex-1 flex flex-col items-center gap-2">
                  <div className="w-full bg-slate-50 rounded-lg overflow-hidden flex flex-col justify-end h-full">
                    <div className={`w-full transition-all duration-1000 rounded-t-lg ${val > 80 ? 'bg-emerald-400' : val > 50 ? 'bg-blue-400' : 'bg-rose-400'}`} style={{ height: `${val}%` }}></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-300">{"MTWTFSS"[i]}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-rose-600 text-white p-8 rounded-[2rem] shadow-xl shadow-rose-100 relative overflow-hidden group">
            <div className="absolute -bottom-4 -right-4 w-24 h-24 bg-white/10 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
            <h3 className="font-black text-xl flex items-center gap-3 mb-3">
              Emergency
            </h3>
            <p className="text-sm opacity-90 font-medium mb-6">Need immediate help? Alert your caretaker now.</p>
            <button className="w-full bg-white text-rose-600 py-4 rounded-2xl font-black shadow-lg hover:bg-slate-50 active:scale-[0.98] transition-all">
              Send Panic Alert
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PatientDashboard;

import React, { useState, useRef, useEffect } from 'react';
import { Icons } from '../constants';
import { getGeminiAdvisor } from '../services/geminiService';

interface MediBotProps {
  userName: string;
}

const MediBot: React.FC<MediBotProps> = ({ userName }) => {
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: `Hello ${userName.split(' ')[0]}! I am MediBot. How can I help you with your health or medicines today?` }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const response = await getGeminiAdvisor(userMsg);
      setMessages(prev => [...prev, { role: 'bot', text: response || "I'm sorry, I couldn't process that. Please try again." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "Error connecting to AI. Please check your internet." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-160px)] flex flex-col bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="p-5 border-b border-slate-100 bg-slate-50 flex items-center gap-3">
        <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
          <Icons.Bot />
        </div>
        <div>
          <h2 className="font-black text-slate-800 tracking-tight">MediBot AI</h2>
          <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest flex items-center gap-1.5">
            <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span> Active
          </p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-[1.5rem] px-5 py-4 text-sm font-medium leading-relaxed shadow-sm ${
              m.role === 'user' 
              ? 'bg-blue-600 text-white rounded-tr-none shadow-blue-100' 
              : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
            }`}>
              {m.text}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-white border border-slate-100 rounded-[1.5rem] px-5 py-4 text-slate-400 text-sm font-bold italic flex items-center gap-3 shadow-sm">
              <div className="flex gap-1">
                <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
              Thinking...
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-white border-t border-slate-100">
        <div className="flex gap-3">
          <input 
            type="text" 
            placeholder="Ask about side effects, dosage, or health tips..."
            className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all font-medium"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button 
            onClick={handleSend}
            disabled={loading}
            className="bg-blue-600 text-white p-4 rounded-2xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-100 disabled:opacity-50 active:scale-90"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg>
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-4 font-bold uppercase tracking-widest italic opacity-70">
          Not a substitute for professional medical advice.
        </p>
      </div>
    </div>
  );
};

export default MediBot;

import React, { useState, useEffect } from 'react';
import { Medicine, IntakeLog } from '../types';
import { Icons } from '../constants';
import { getAdherenceReport } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface DoctorReportsProps {
  medicines: Medicine[];
  logs: IntakeLog[];
  userName: string;
}

const DoctorReports: React.FC<DoctorReportsProps> = ({ medicines, logs, userName }) => {
  const [aiAnalysis, setAiAnalysis] = useState<{summary: string, score: number, alerts: string[]} | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchReport = async () => {
      setLoading(true);
      try {
        const report = await getAdherenceReport(logs, medicines);
        setAiAnalysis(report);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchReport();
  }, [logs, medicines]);

  const data = medicines.map(med => {
    const medLogs = logs.filter(l => l.medicineId === med.id);
    const takenCount = medLogs.filter(l => l.status === 'taken').length;
    const missedCount = medLogs.filter(l => l.status === 'missed').length;
    const total = takenCount + missedCount || 1;
    return {
      name: med.name,
      adherence: Math.round((takenCount / total) * 100),
      missed: missedCount
    };
  });

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header>
        <h1 className="text-3xl font-black text-slate-900 tracking-tight">Health Compliance</h1>
        <p className="text-slate-500 font-medium">Monitoring data for: <span className="text-blue-600 font-bold">{userName}</span></p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center justify-center text-center">
          <div className="relative w-52 h-52 flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="104" cy="104" r="94" stroke="currentColor" strokeWidth="16" fill="transparent" className="text-slate-50" />
              <circle 
                cx="104" cy="104" r="94" stroke="currentColor" strokeWidth="16" fill="transparent" 
                strokeDasharray={590}
                strokeDashoffset={590 - (590 * (aiAnalysis?.score || 0)) / 100}
                className={`${(aiAnalysis?.score || 0) > 80 ? 'text-emerald-500' : 'text-blue-500'} transition-all duration-1000 ease-out rounded-full`}
                strokeLinecap="round"
              />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-5xl font-black text-slate-900">{aiAnalysis?.score || '--'}%</span>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-1">Consistency</span>
            </div>
          </div>
          <p className="mt-8 text-slate-500 font-bold text-sm uppercase tracking-widest">
            Last 30 Days Record
          </p>
        </div>

        <div className="bg-slate-900 text-white p-10 rounded-[2.5rem] shadow-2xl shadow-slate-300 relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-12 opacity-5 scale-150 group-hover:rotate-12 transition-transform duration-700">
            <Icons.Bot />
          </div>
          <h3 className="text-xl font-black mb-6 flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center scale-90">
              <Icons.Bot />
            </div>
            Smart Insights
          </h3>
          {loading ? (
            <div className="space-y-4 animate-pulse">
              <div className="h-4 bg-slate-800 rounded-full w-3/4"></div>
              <div className="h-4 bg-slate-800 rounded-full w-full"></div>
              <div className="h-4 bg-slate-800 rounded-full w-5/6"></div>
            </div>
          ) : (
            <div className="space-y-8 relative z-10">
              <p className="text-slate-300 leading-relaxed font-medium italic text-lg">
                "{aiAnalysis?.summary || 'Analyzing historical patterns...'}"
              </p>
              <div className="space-y-4">
                <p className="text-xs font-black text-blue-400 uppercase tracking-widest">Priority Alerts</p>
                <ul className="space-y-3">
                  {(aiAnalysis?.alerts || []).map((alert, i) => (
                    <li key={i} className="flex items-start gap-3 text-sm font-bold text-slate-100">
                      <span className="mt-1.5 w-2 h-2 bg-rose-500 rounded-full shrink-0 shadow-lg shadow-rose-900"></span>
                      {alert}
                    </li>
                  ))}
                  {(!aiAnalysis?.alerts.length) && (
                    <li className="text-slate-500 text-sm font-bold italic">No critical alerts detected.</li>
                  )}
                </ul>
              </div>
            </div>
          )}
        </div>

        <div className="lg:col-span-2 bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50">
          <h3 className="text-xl font-black text-slate-800 mb-10 flex items-center gap-3">
            <Icons.Chart />
            Adherence Breakdown
          </h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="0" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 700}} dy={15} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 700}} domain={[0, 100]} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', padding: '15px'}}
                  itemStyle={{fontWeight: 900, color: '#1e293b'}}
                />
                <Bar dataKey="adherence" radius={[12, 12, 0, 0]} barSize={45}>
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.adherence > 80 ? '#10b981' : '#3b82f6'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DoctorReports;
